/**
 * Create new elements through drag and drop.
 *
 */
export default class Create {
    static $inject: string[];
    /**
     * @param canvas
     * @param dragging
     * @param eventBus
     * @param modeling
     * @param rules
     */
    constructor(canvas: Canvas, dragging: Dragging, eventBus: EventBus, modeling: Modeling, rules: Rules);
    /**
     * @param event
     * @param elements
     * @param context
     */
    start: (event: any, elements: any, context?: any) => void;
}

type Element = import("../../core/Types.js").ElementLike;
type Shape = import("../../core/Types.js").ShapeLike;
type Point = import("../../util/Types.js").Point;
type Canvas = import("../../core/Canvas.js").default;
type Dragging = import("../dragging/Dragging.js").default;
type EventBus = import("../../core/EventBus.js").default;
type Modeling = import("../modeling/Modeling.js").default;
type Rules = import("../rules/Rules.js").default;